final class DataImportProcessor {

    private DataImportProcessor() {
    }

    static ImportResult process(ImportRequest request) {
        ImportResult result = new ImportResult();
        result.setRequestId(request.getRequestId());
        result.setCorrelationId(request.getCorrelationId());
        result.setSourceSystem(request.getSourceSystem());
        result.setProcessedAt(Instant.now().toString());

        int total = 0;
        int success = 0;
        int failure = 0;
        List<EntityProcessingResult> details = new ArrayList<>();

        List<ImportEntity> flatEntities = flatten(request.getEntities());
        for (List<ImportEntity> batch : partition(flatEntities, DEFAULT_BATCH_SIZE)) {
            for (ImportEntity entity : batch) {
                total++;
                EntityProcessingResult entityResult = processEntity(entity, request);
                details.add(entityResult);
                if ("SUCCESS".equals(entityResult.getStatus())) {
                    success++;
                } else {
                    failure++;
                }
            }
        }

        result.setTotalEntities(total);
        result.setSuccessfulEntities(success);
        result.setFailedEntities(failure);
        result.setEntityResults(details);
        result.setStatus(failure == 0 ? "SUCCESS" : (success > 0 ? "PARTIAL_SUCCESS" : "FAILED"));

        return result;
    }

    private static EntityProcessingResult processEntity(ImportEntity entity, ImportRequest request) {
        EntityProcessingResult result = new EntityProcessingResult();
        result.setEntityType(entity.getType());
        result.setExternalId(entity.getExternalId());
        result.setOperation(entity.getOperation());

        try {
            validateEntity(entity);
            String generatedId = generateRecordId(entity);
            result.setRecordId(generatedId);
            result.setStatus("SUCCESS");
            result.setMessage("Entity processed successfully");
            result.setImportedFieldCount(entity.getFields() != null ? entity.getFields().size() : 0);
            result.setRelationshipCount(entity.getRelationships() != null ? entity.getRelationships().size() : 0);
        } catch (Exception e) {
            result.setStatus("FAILED");
            result.setMessage(e.getMessage());
            result.setImportedFieldCount(0);
            result.setRelationshipCount(0);
        }

        return result;
    }

    private static void validateEntity(ImportEntity entity) {
        if (entity.getType() == null || entity.getType().isEmpty()) {
            throw new IllegalArgumentException("Entity type is required");
        }
        if (entity.getFields() == null || entity.getFields().isEmpty()) {
            throw new IllegalArgumentException("Entity fields are required for type: " + entity.getType());
        }
    }

    private static String generateRecordId(ImportEntity entity) {
        String seed = entity.getType() + "|" + entity.getExternalId() + "|" + entity.getOperation() + "|" + System.nanoTime();
        return UUID.nameUUIDFromBytes(seed.getBytes(StandardCharsets.UTF_8)).toString();
    }

    private static List<ImportEntity> flatten(List<ImportEntity> entities) {
        List<ImportEntity> result = new ArrayList<>();
        if (entities == null) {
            return result;
        }
        for (ImportEntity entity : entities) {
            result.add(entity);
            if (entity.getNestedEntities() != null && !entity.getNestedEntities().isEmpty()) {
                result.addAll(flatten(entity.getNestedEntities()));
            }
        }
        return result;
    }

    private static <T> List<List<T>> partition(List<T> source, int size) {
        List<List<T>> partitions = new ArrayList<>();
        if (source == null || source.isEmpty() || size <= 0) {
            return partitions;
        }
        for (int i = 0; i < source.size(); i += size) {
            partitions.add(source.subList(i, Math.min(i + size, source.size())));
        }
        return partitions;
    }
}

final class SoapResponseFactory {

    private SoapResponseFactory() {
    }

    static SOAPMessage successResponse(ImportResult result) {
        try {
            MessageFactory messageFactory = MessageFactory.newInstance();
            SOAPMessage message = messageFactory.createMessage();
            SOAPEnvelope envelope = message.getSOAPPart().getEnvelope();
            SOAPBody body = envelope.getBody();

            SOAPElement response = body.addChildElement(RESPONSE_ELEMENT, "ns1", "http://enterprise.integration.soap/");
            addChild(response, "RequestId", result.getRequestId());
            addChild(response, "CorrelationId", result.getCorrelationId());
            addChild(response, "SourceSystem", result.getSourceSystem());
            addChild(response, "Status", result.getStatus());
            addChild(response, "ProcessedAt", result.getProcessedAt());
            addChild(response, "TotalEntities", String.valueOf(result.getTotalEntities()));
            addChild(response, "SuccessfulEntities", String.valueOf(result.getSuccessfulEntities()));
            addChild(response, "FailedEntities", String.valueOf(result.getFailedEntities()));

            SOAPElement entityResults = response.addChildElement("EntityResults");
            for (EntityProcessingResult item : result.getEntityResults()) {
                SOAPElement entity = entityResults.addChildElement("EntityResult");
                addChild(entity, "EntityType", item.getEntityType());
                addChild(entity, "ExternalId", item.getExternalId());
                addChild(entity, "Operation", item.getOperation());
                addChild(entity, "RecordId", item.getRecordId());
                addChild(entity, "Status", item.getStatus());
                addChild(entity, "Message", item.getMessage());
                addChild(entity, "ImportedFieldCount", String.valueOf(item.getImportedFieldCount()));
                addChild(entity, "RelationshipCount", String.valueOf(item.getRelationshipCount()));
            }

            message.saveChanges();
            return message;
        } catch (SOAPException e) {
            throw new RuntimeException("Failed to create SOAP response", e);
        }
    }

    static SOAPMessage faultResponse(String code, String messageText) {
        try {
            MessageFactory messageFactory = MessageFactory.newInstance();
            SOAPMessage message = messageFactory.createMessage();
            SOAPBody body = message.getSOAPBody();
            SOAPFault fault = body.addFault();
            fault.setFaultCode(new QName("http://enterprise.integration.soap/", code));
            fault.setFaultString(messageText != null ? messageText : "Unknown error");
            message.saveChanges();
            return message;
        } catch (SOAPException e) {
            throw new RuntimeException("Failed to create SOAP fault", e);
        }
    }

    private static void addChild(SOAPElement parent, String name, String value) throws SOAPException {
        SOAPElement child = parent.addChildElement(name);
        child.addTextNode(value != null ? value : "");
    }
}

